const update = $input.item.json;
const isTelegram = !!update.message;
const isWebsite = !!update.body;

let result;
if (isTelegram) {
  const msg = update.message || update.callback_query?.message;
  const cbq = update.callback_query;
  result = {
    source: 'telegram',
    userId: String(msg?.from?.id || 'unknown'),
    sessionId: 'sess_' + String(msg?.chat?.id || '0') + '_' + Date.now(),
    messageId: String(msg?.message_id || ''),
    inputType: msg?.voice ? 'voice' : msg?.photo ? 'photo' : msg?.document ? 'document' : msg?.location ? 'location' : msg?.text ? 'text' : 'unknown',
    inputText: msg?.text || msg?.caption || cbq?.data || '',
    inputBinary: null,
    metadata: {
      chatId: String(msg?.chat?.id || ''),
      replyEndpoint: null,
      timestamp: new Date().toISOString(),
      clientInfo: { firstName: msg?.from?.first_name, username: msg?.from?.username }
    }
  };
} else if (isWebsite) {
  const body = update.body || {};
  result = {
    source: 'website',
    userId: 'default',
    sessionId: body.session_id || 'sess_default_' + Date.now(),
    messageId: body.message_id || '',
    inputType: body.input_type || 'text',
    inputText: body.text || body.message || '',
    inputBinary: body.attachment || null,
    metadata: {
      chatId: null,
      replyEndpoint: body.reply_url || null,
      timestamp: new Date().toISOString(),
      clientInfo: body.client_info || {}
    }
  };
} else {
  return [];
}

return [{ json: result }];

const OWNER_ID = String($env.OWNER_USER_ID || '');
const MODE = String($env.AUTH_MODE || 'open').toLowerCase();
const userId = String($json.userId || '');

if ($env.TELEGRAM_WEBHOOK_SECRET) {
  const trigger = $('Telegram Trigger').first();
  const headers = trigger?.json?.headers || {};
  const secret = headers['x-telegram-bot-api-secret-token'];
  if (!secret || secret !== $env.TELEGRAM_WEBHOOK_SECRET) {
    return [];
  }
}

if (MODE === 'protected' && OWNER_ID && userId !== OWNER_ID) {
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
      headers: { 'Content-Type': 'application/json' },
      body: { chat_id: $json.metadata?.chatId, text: '⛔ Access denied.' },
      timeout: 5000
    });
  } catch (e) {}
  return [];
}

return [$input.item];

const userId = String($json.userId || 'default');
const limit = parseInt($env.RATE_LIMIT_PER_MINUTE || '30', 10);
const WINDOW = 60_000;
const now = Date.now();

const sd = $getWorkflowStaticData('global');
sd.rl = sd.rl || {};
const bucket = sd.rl[userId] || (sd.rl[userId] = []);
while (bucket.length && (now - bucket[0]) > WINDOW) bucket.shift();

if (bucket.length >= limit) {
  return [];
}
bucket.push(now);
return [{ json: { ...$json, startTime: now } }];
